    public class InputValidator : IInputValidator
    {
        private static readonly Regex PatientIdRegex = new Regex(@"^[A-Z0-9]{8,20}$", RegexOptions.Compiled);
        private static readonly Regex RequesterIdRegex = new Regex(@"^[A-Z0-9]{8,20}$", RegexOptions.Compiled);
        private static readonly Regex NameRegex = new Regex(@"^[a-zA-Z\s\-']{1,50}$", RegexOptions.Compiled);
        private static readonly Regex SSNRegex = new Regex(@"^\d{3}-\d{2}-\d{4}$", RegexOptions.Compiled);

        public bool ValidatePatientId(string patientId)
        {
            return !string.IsNullOrWhiteSpace(patientId) && PatientIdRegex.IsMatch(patientId);
        }

        public bool ValidateRequesterId(string requesterId)
        {
            return !string.IsNullOrWhiteSpace(requesterId) && RequesterIdRegex.IsMatch(requesterId);
        }

        public bool ValidatePatientRecord(PatientRecord record)
        {
            if (record == null) return false;

            if (!string.IsNullOrWhiteSpace(record.FirstName) && !NameRegex.IsMatch(record.FirstName))
                return false;

            if (!string.IsNullOrWhiteSpace(record.LastName) && !NameRegex.IsMatch(record.LastName))
                return false;

            if (!string.IsNullOrWhiteSpace(record.SSN) && !SSNRegex.IsMatch(record.SSN))
                return false;

            if (record.DateOfBirth > DateTime.Now || record.DateOfBirth < new DateTime(1900, 1, 1))
                return false;

            if (!string.IsNullOrWhiteSpace(record.Diagnosis) && record.Diagnosis.Length > 1000)
                return false;

            if (!string.IsNullOrWhiteSpace(record.Medications) && record.Medications.Length > 1000)
                return false;

            if (!string.IsNullOrWhiteSpace(record.Allergies) && record.Allergies.Length > 500)
                return false;

            return true;
        }
    }

