    // Custom X509 Certificate Validator
    public class CustomX509CertificateValidator : X509CertificateValidator
    {
        private readonly HashSet<string> _trustedThumbprints;

        public CustomX509CertificateValidator()
        {
            _trustedThumbprints = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
            {
                // Add trusted certificate thumbprints
            };
        }

        public override void Validate(X509Certificate2 certificate)
        {
            if (certificate == null)
                throw new ArgumentNullException(nameof(certificate));

            // Validate certificate is not expired
            if (DateTime.Now < certificate.NotBefore || DateTime.Now > certificate.NotAfter)
                throw new SecurityTokenValidationException("Certificate is expired or not yet valid");

            // Validate certificate chain
            var chain = new X509Chain
            {
                ChainPolicy = new X509ChainPolicy
                {
                    RevocationMode = X509RevocationMode.Online,
                    RevocationFlag = X509RevocationFlag.EntireChain,
                    VerificationFlags = X509VerificationFlags.NoFlag
                }
            };

            if (!chain.Build(certificate))
            {
                throw new SecurityTokenValidationException("Certificate chain validation failed");
            }

            // Additional custom validation
            if (_trustedThumbprints.Count > 0 && !_trustedThumbprints.Contains(certificate.Thumbprint))
            {
                throw new SecurityTokenValidationException("Certificate is not in trusted list");
            }
        }
    }

